/**
 * 1. ดึงผลลัพธ์จาก AI Agent
 * โดยปกติจะอยู่ในฟิลด์ 'output' แต่เราดักเผื่อไว้หลายๆ ทาง
 */
const aiOutput = $json.output || $json.text || "{}";
let parsedAI;

// 2. พยายามแปลง String (JSON) ที่ AI ส่งมาให้กลายเป็น Object
try {
  // ถ้าเป็น String ให้ Parse แต่ถ้าเป็น Object อยู่แล้วก็ใช้ได้เลย
  parsedAI = typeof aiOutput === 'string' ? JSON.parse(aiOutput) : aiOutput;
} catch (e) {
  // ถ้า AI ดื้อ ส่ง JSON พังมา ให้เก็บค่าดิบไว้ตรวจสอบ
  parsedAI = { 
    ticket_no: null, 
    error: "AI_FORMAT_ERROR", 
    raw_response: aiOutput 
  };
}

/**
 * 3. รวมร่างข้อมูล (Merge) 
 * ดึงค่า userId และข้อมูลดั้งเดิมจากโหนด JavaScript2 กลับคืนมา
 */
return [{
  json: {
    ...parsedAI, // ข้อมูลที่ AI สรุป (ticket_no, severity, fault_date, etc.)

    // ดึง userId จากโหนด JavaScript2 (โหนดก่อนหน้า AI)
    userId: $node["Code in JavaScript2"].json.userId || "Unknown",

    // ดึงรูปภาพกลับมา (ถ้ามี)
    close_image: $node["Code in JavaScript2"].json.original_data?.close_image || null,

    processed_at: $now.format('YYYY-MM-DD HH:mm:ss') // ใส่เวลาที่ประมวลผลเสร็จ
  }
}];

function safeParse(raw) {
  if (!raw) return null;

  // ถ้าเป็น object อยู่แล้ว
  if (typeof raw === "object") return raw;

  if (typeof raw !== "string") return null;

  try {
    const cleaned = raw
      .replace(/^```json\s*/i, '')
      .replace(/```$/i, '')
      .trim();

    return JSON.parse(cleaned);
  } catch (e) {
    return null;
  }
}

const original = $json; // ✅ เก็บข้อมูลเดิมทั้งหมด (userId, replyToken ฯลฯ)
const parsed = safeParse(original.finalMessage);

const requiredKeys = [
  "ticket_no",
  "severity",
  "fault_date",
  "expected_date",
  "owner",
  "go_time",
  "start_time",
  "done_time",
  "status"
];

// ❌ กรณี AI ส่ง JSON ไม่ถูก
if (!parsed) {
  return [{
    json: {
      ...original,
      error: true,
      message: "❌ AI ส่ง JSON ไม่ถูกต้อง"
    }
  }];
}

// ❌ กรณี key ไม่ครบ
for (const key of requiredKeys) {
  if (!(key in parsed)) {
    return [{
      json: {
        ...original,
        error: true,
        message: `❌ JSON structure ไม่ครบ (ขาด ${key})`
      }
    }];
  }
}

// ✅ สำเร็จ → merge ของเดิม + parsed
return [{
  json: {
    ...original,  // ✅ เก็บ userId / replyToken / source
    ...parsed     // ✅ ทับด้วยข้อมูลที่ parse แล้ว
  }
}];

