const d = $json;

// 1. จัดการ Timeline: ถ้ามีข้อมูลให้ขึ้นบรรทัดใหม่และใส่ไอคอน 🕒
const timelineDisplay = d.timeline ? `\n\n🕒 **Timeline:**\n${d.timeline}` : "";

// 2. จัดการ Cause/Fix: ถ้าไม่มีข้อมูลให้แสดงว่า "-" เพื่อความสวยงาม
const causeText = d.cause || "-";
const fixText = d.fix || "-";

const message = `
✅ **ปิดงานเรียบร้อย**

📌 **Ticket:** ${d.ticket_no}
⚡ **Severity:** ${d.severity}
🌍 **Province:** ${d.province}

📅 **Fault Date:** ${d.fault_date}
📆 **Expected:** ${d.expected_date}

🕒 **Time:** ${d.go_time} - ${d.done_time}
(Start: ${d.start_time})

🔧 **Cause:** ${causeText}
🛠 **Fix:** ${fixText}

📍 **Location:** ${d.location}
🔗 **Map:** ${d.map_link}

👨‍🔧 **Technician:** ${d.technician}${timelineDisplay}

#CloseJob
`;

return [
  {
    json: {
      ...d,      // รักษาข้อมูลเดิมทั้งหมด (lat, lng, ticket_no ฯลฯ)
      message    // ส่งข้อความที่ประกอบร่างแล้วไปที่ LINE หรือ Sheets
    }
  }
];

return [{
  json: {
    ...$json,
    // ดึงเลข Ticket จากโหนด Detect Mode มาดักไว้
    ticket_no: $node["Detect Mode"].json["ticket_no"], 
    // เก็บลิงก์รูปภาพ
    close_image: $json.webViewLink || $json.webContentLink || $json.id
  }
}];

const messageBody = $json.message?.text || $json.text || $json.full_text || "";
const text = messageBody.trim();

if (!text) {
    return { json: { ...$json, status: "NO_TEXT_FOUND" } };
}

let timeline = [], cause = "", fix = "", go_time = "", start_time = "", done_time = "";
let ticket_no = "", technician = "", province = "", location = "", fault_date = "", expected_date = "";
let readCause = false, readFix = false, readTimeline = false;

const lines = text.split("\n");

for (const raw of lines) {
    const line = raw.trim();
    if (!line) continue;

    // 1. ตรวจสอบหัวข้อ (Section Headers)
    if (/^cause/i.test(line)) { readCause = true; readFix = false; readTimeline = false; continue; }
    if (/^fix/i.test(line)) { readFix = true; readCause = false; readTimeline = false; continue; }
    if (/^timeline/i.test(line)) { readTimeline = true; readCause = false; readFix = false; continue; }

    // 2. ดึงข้อมูลรายบรรทัดด้วย Regex
    const ticketMatch = line.match(/TT\d+/i);
    const goMatch     = line.match(/go\s*time\s*[:\-]\s*(\d{1,2}[.:]\d{2})/i);
    const startMatch  = line.match(/start\s*time\s*[:\-]\s*(\d{1,2}[.:]\d{2})/i);
    const doneMatch   = line.match(/done\s*time\s*[:\-]\s*(\d{1,2}[.:]\d{2})/i); 
    const techMatch   = line.match(/technician\s*[:\-]\s*(.*)/i);
    const provMatch   = line.match(/province\s*[:\-]\s*(.*)/i);
    const faultMatch  = line.match(/fault\s*date\s*[:\-]\s*(.*)/i);
    const expMatch    = line.match(/expected\s*date\s*[:\-]\s*(.*)/i);
    const locMatch    = line.match(/(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/);

    const isNewField = /^\w+(\s+\w+)?\s*[:\-]/i.test(line);

    if (ticketMatch) { ticket_no = ticketMatch[0].toUpperCase(); }
    if (goMatch)     { go_time = goMatch[1].replace(".", ":"); readCause = false; readFix = false; }
    if (startMatch)  { start_time = startMatch[1].replace(".", ":"); readCause = false; readFix = false; }
    if (doneMatch)   { done_time = doneMatch[1].replace(".", ":"); readCause = false; readFix = false; }
    if (techMatch)   { technician = techMatch[1].trim(); readCause = false; readFix = false; }
    if (provMatch)   { province = provMatch[1].trim(); readCause = false; readFix = false; }
    if (faultMatch)  { fault_date = faultMatch[1].trim(); readCause = false; readFix = false; }
    if (expMatch)    { expected_date = expMatch[1].trim(); readCause = false; readFix = false; }
    if (locMatch)    { location = locMatch[0]; }

    if (/^\d{1,2}[.:]\d{2}/.test(line) || (readTimeline && !isNewField)) {
        timeline.push(line);
        continue;
    }

    if (readCause && !isNewField) cause += line + " ";
    if (readFix && !isNewField) fix += line + " ";
}

let [lat, lng] = location.includes(",") ? location.split(",").map(s => s.trim()) : ["", ""];

return {
    json: {
        ...$json,
        ticket_no, fault_date, expected_date, technician, province,
        go_time, start_time, done_time, location, lat, lng,
        cause: cause.trim(), fix: fix.trim(), timeline: timeline.join("\n"),
        severity: "Normal", open_ticket: "true", status: "CLOSED"
    }
};

const parsed =
$node["Parse close job1"]?.json ||
$node["Save Work Detail1"]?.json ||
{};

const imageUrl =
$json.webViewLink ||
$json.webContentLink ||
"";

const userId =
$node["Line Messaging Trigger1"]?.json?.source?.userId ||
$node["Line Messaging Trigger1"]?.json?.events?.[0]?.source?.userId ||
"";

return [{
json:{
...parsed,
image_url: imageUrl,
userId: userId,
timestamp: new Date().toISOString()
}
}];

