// ดึงข้อความจาก LINE
const messageBody = $json.message?.text || $json.text || $json.full_text || "";
const text = messageBody.trim();

if (!text) {
  return {
    json: {
      ...$json,
      status: "NO_TEXT_FOUND"
    }
  };
}

// ตัวแปรเก็บข้อมูล
let timeline = [];
let cause = "";
let fix = "";

let go_time = "";
let start_time = "";
let done_time = "";

let ticket_no = "";
let technician = "";
let province = "";
let location = "";

let fault_date = "";
let expected_date = "";

let severity = "";

// ⭐ ต้องประกาศตรงนี้ก่อนใช้
let lat = "";
let lng = "";

let readCause = false;
let readFix = false;
let readTimeline = false;

const lines = text.split("\n");

for (const raw of lines) {

  const line = raw.trim();
  if (!line) continue;

  // SECTION
  if (/^cause/i.test(line)) {
    readCause = true;
    readFix = false;
    readTimeline = false;
    continue;
  }

  if (/^fix/i.test(line)) {
    readFix = true;
    readCause = false;
    readTimeline = false;
    continue;
  }

  if (/^timeline/i.test(line)) {
    readTimeline = true;
    readCause = false;
    readFix = false;
    continue;
  }

  // REGEX
  const ticketMatch = line.match(/TT\d+/i);

  const goMatch = line.match(/go\s*time\s*[:\-]\s*(\d{1,2}[.:]\d{2})/i);
  const startMatch = line.match(/start\s*time\s*[:\-]\s*(\d{1,2}[.:]\d{2})/i);
  const doneMatch = line.match(/done\s*time\s*[:\-]\s*(\d{1,2}[.:]\d{2})/i);

  const techMatch = line.match(/technician\s*[:\-]\s*(.*)/i);
  const provMatch = line.match(/province\s*[:\-]\s*(.*)/i);

  const faultMatch = line.match(/fault\s*date\s*[:\-]\s*(.*)/i);
  const expMatch = line.match(/expected\s*date\s*[:\-]\s*(.*)/i);

  // lat lng แบบตัวเลข
  const locMatch = line.match(/(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/);

  // Google maps link
  const mapLinkMatch = line.match(/@(-?\d+\.\d+),(-?\d+\.\d+)/);
  const mapQueryMatch = line.match(/[?&](?:q|ll)=(-?\d+\.\d+),(-?\d+\.\d+)/);

  const sevMatch = line.match(/severity\s*[:\-]\s*(\S+)/i);

  const isNewField = /^\w+(\s+\w+)?\s*[:\-]/i.test(line);

  // Ticket
  if (ticketMatch) ticket_no = ticketMatch[0].toUpperCase();

  // เวลา
  if (goMatch) go_time = goMatch[1].replace(".", ":");
  if (startMatch) start_time = startMatch[1].replace(".", ":");
  if (doneMatch) done_time = doneMatch[1].replace(".", ":");

  // Technician
  if (techMatch) technician = techMatch[1].trim();

  // Province
  if (provMatch) province = provMatch[1].trim();

  // Fault date
  if (faultMatch) {
    fault_date = faultMatch[1].trim().split(" ")[0];
  }

  // Expected date
  if (expMatch) {
    expected_date = expMatch[1].trim().split(" ")[0];
  }

  // Lat Lng ตรงๆ
  if (locMatch) {
    lat = locMatch[1];
    lng = locMatch[2];
    location = `${lat},${lng}`;
  }

  // Google Maps @lat,lng
  if (mapLinkMatch) {
    lat = mapLinkMatch[1];
    lng = mapLinkMatch[2];
    location = `${lat},${lng}`;
  }

  // Google Maps ?q=lat,lng
  if (mapQueryMatch) {
    lat = mapQueryMatch[1];
    lng = mapQueryMatch[2];
    location = `${lat},${lng}`;
  }

  // severity
  if (sevMatch) {
    severity = sevMatch[1].toUpperCase();
  }

  // TIMELINE
  if (/^\d{1,2}[.:]\d{2}/.test(line) || (readTimeline && !isNewField)) {
    timeline.push(line);
    continue;
  }

  // Cause
  if (readCause && !isNewField) {
    cause += line + " ";
  }

  // Fix
  if (readFix && !isNewField) {
    fix += line + " ";
  }

}

return {
  json: {
    ...$json,

    ticket_no,
    fault_date,
    expected_date,

    technician,
    province,

    go_time,
    start_time,
    done_time,

    location,
    lat,
    lng,

    cause: cause.trim(),
    fix: fix.trim(),

    timeline: timeline.join("\n"),

    severity: severity || "",

    open_ticket: "true",
    status: "CLOSED"
  }
};

